const QUIZ_QUESTIONS_BANK = [
  {id:1,chapter:1,question:"מה היא מטרתו העיקרית של תקן 'יסודות מנצחים'?",options:["לקבוע את מספר הצוערים בכל מחזור","ליצור סטנדרט אחיד בתהליכי הליבה המרכזיים ביחידות ההדרכה","להגדיר את שכר המפקדים בהכשרות","לקבוע לוח זמנים שנתי לכלל הצבא"],correctAnswer:1,explanation:"התקן נכתב מתוך הצורך ליצור סטנדרט אחיד בתהליכי הליבה המרכזיים ביחידות ההדרכה, ומיועד בראש ובראשונה למפקדים בהכשרות.",source:"הקדמה, עמ' 5"},
  {id:2,chapter:1,question:"מי רשאי להחזיק בחוברת נהלי התקן?",options:["כל חייל בבהד","מפקדים מדרג מ\"פ ומעלה או מקבילו","קצינים בלבד","רק מפקד הבהד"],correctAnswer:1,explanation:"חוברת נהלי התקן נדרשת להימצא בידי כל מפקד מדרג מ\"פ ומעלה או מקבילו.",source:"הקדמה, עמ' 5, סעיף ג'"},
  {id:3,chapter:1,question:"מי חותם על מסמך החרגה מנהלי התקן?",options:["מפקד הגדוד בלבד","ענף הדרכה בלבד","מפקד הבהד, ואישור הגורם הזרועי המוסמך","מפקד הפלוגה"],correctAnswer:2,explanation:"מסמך ההחרגה יחתם על-ידי מפקד הבה\"ד ויאושר על-ידי הגורם הזרועי המוסמך – ענף הכשרות בפיקוד האימונים וההכשרות של ז\"י.",source:"הקדמה, עמ' 6"},
  {id:4,chapter:1,question:"מי מתעד את כלל מסמכי ההחרגה מהתקן?",options:["קצין האגם","מפקד גוף פיתוח ההדרכה ביחידה","קצין הצפה","שלישית מפקד הבהד"],correctAnswer:1,explanation:"כלל מסמכי ההחרגה נדרשים להיות מתועדים באחריות מפקד גוף פיתוח ההדרכה ביחידה.",source:"הקדמה, עמ' 6, סעיף ד'"},
  {id:5,chapter:1,question:"כמה פעמים בשנה מתבצעות בקרות חיצוניות ברמת זרוע היבשה?",options:["פעמיים בשנה","אחת לשנה","אחת לשנתיים","אחת לרבעון"],correctAnswer:1,explanation:"בקרות חיצוניות ברמת זרוע היבשה – בתדירות של אחת לשנה.",source:"הקדמה, עמ' 6"},
  {id:6,chapter:1,question:"מה תדירות הסיקור המטכ\"לי (תל\"ב) של יחידות הכשרה?",options:["אחת לשנה","אחת לשנה וחצי","אחת לשנתיים","אחת לשלוש שנים"],correctAnswer:2,explanation:"ברמה מטכ\"לית – סיקור תל\"ב אחת לשנתיים.",source:"הקדמה, עמ' 6"},
  {id:7,chapter:1,question:"מהו 'שעון פעילות' ביחידת הדרכה?",options:["לוח שעות יומי לצוערים","גרף המגדיר את עיתוי מופעי ניהול ההדרכה המרכזיים בהכשרה","לוח זמנים לתורנויות","מערכת שעות שבועית"],correctAnswer:1,explanation:"שעון פעילות הוא גרף המגדיר את העיתוי של מופעי ניהול ההדרכה המרכזיים בהכשרה.",source:"נוהל 1.2, עמ' 12"},
  {id:8,chapter:1,question:"מה מגדיר 'גרף הכשרות' לפי נוהל 1.2?",options:["לוח שיעורים יומי","גרף הכולל עיתויי פתיחה וסיום ההכשרות ומופעי הכנות מפקדים","לוח ביקורות","לוח חגים וימי ציון"],correctAnswer:1,explanation:"גרף הכשרות הוא גרף הכולל את עיתויי הפתיחה והסיום של ההכשרות וכן מופעי הכנות מפקדים וגורמים משפיעים נוספים. מנוהל ע\"י אג\"ם הבה\"ד.",source:"נוהל 1.2, עמ' 12"},
  {id:9,chapter:1,question:"מהו 'אבחון הדרכתי מלא'?",options:["בדיקת מבחן אחד בהכשרה","תהליך שיטתי וסדור של איסוף ומיפוי נתונים לצורך איתור צרכי הדרכה בארגון כולו","ביקורת חיצונית של הזרוע","בחינה של מפקד אחד"],correctAnswer:1,explanation:"אבחון הדרכתי מלא הוא תהליך שיטתי וסדור של איסוף ומיפוי נתונים לצורך איתור צרכי הדרכה בארגון כולו.",source:"נוהל 1.3, עמ' 14"},
  {id:10,chapter:1,question:"מהו 'צורך הדרכתי' לפי התקן?",options:["כל רצון של מפקד ללמד נושא חדש","בעיה או פער בביצוע שפתרונו אפשרי על-ידי התערבות הדרכתית","שינוי בתו\"ל","דרישה מהחיל"],correctAnswer:1,explanation:"צורך הדרכתי – בעיה או פער בביצוע או בתהליך שפתרונו אפשרי על-ידי התערבות הדרכתית.",source:"נוהל 1.3, עמ' 14"},
  {id:11,chapter:1,question:"באיזה רבעון של שנת הלימודים מבוצע האבחון ההדרכתי השנתי?",options:["רבעון א'","רבעון ב'","רבעון ג'","רבעון ד'"],correctAnswer:3,explanation:"תוכנית האבחון תבוצע ברבעון ד' של שנה\"ע, לקראת גיבוש תוכנית עבודה שנתית.",source:"נוהל 1.3, עמ' 15"},
  {id:12,chapter:1,question:"מהו משך הזמן המרבי לביצוע אבחון הדרכתי?",options:["חודש","חודשיים","שלושה חודשים","חצי שנה"],correctAnswer:2,explanation:"מסגרת הזמנים לביצוע אבחון הינה רבעון (שלושה חודשים) לכל היותר מתחילת התהליך ועד הצגת תוצרים.",source:"נוהל 1.3, עמ' 15"},
  {id:13,chapter:1,question:"מה יחס הדגימה המינימלי של מסגרות פלוגתיות באבחון הדרכתי?",options:["1:1","1:2","1:3","1:4"],correctAnswer:1,explanation:"במסגרת איסוף הנתונים ידגמו מסגרות פלוגתיות ביחס של 1:2 לכל הפחות.",source:"נוהל 1.3, עמ' 15"},
  {id:14,chapter:1,question:"כמה שנים לפחות יש לשמור חומרי אבחון הדרכתי?",options:["שנה","שנתיים","שלוש שנים","חמש שנים"],correctAnswer:2,explanation:"כלל האבחונים וחומרי הגלם ישומרו לכל הפחות למשך שלוש שנים.",source:"נוהל 1.3, עמ' 16"},
  {id:15,chapter:1,question:"עד מתי יש לאשר את תוכנית העבודה ההדרכתית השנתית?",options:["עד 1 בינואר","עד 30 בינואר","עד 28 בפברואר","עד 31 במרץ"],correctAnswer:1,explanation:"תוכנית העבודה ההדרכתית תיכתב ע\"י מפקדת הגפ\"ה ותאושר אצל מפקד הבה\"ד עד לתאריך ה-30.01 בכל שנה.",source:"נוהל 1.4, עמ' 20"},
  {id:16,chapter:1,question:"כמה שנים לפחות יש לשמור תוכניות עבודה הדרכתיות?",options:["שנה","שנתיים","שלוש שנים","ארבע שנים"],correctAnswer:3,explanation:"תוכניות העבודה ההדרכתיות ישמרו למשך 4 שנים לכל הפחות.",source:"נוהל 1.4, עמ' 21"},
  {id:17,chapter:1,question:"כמה שבועות לפני פתיחת מחזור נדרש אישור תוכניות בראשות מפקד הגדוד?",options:["שבוע אחד","שבועיים","שלושה שבועות","חודש"],correctAnswer:2,explanation:"אישור התוכניות בראשות מפקד הגדוד יתבצע לכל הפחות שלושה שבועות טרם פתיחת מחזור ההכשרה.",source:"נוהל 1.5, עמ' 23"},
  {id:18,chapter:1,question:"כמה שבועות לפני פתיחת מחזור נדרש אישור תוכניות בראשות מפקד הבהד?",options:["שבוע אחד","שבועיים","שלושה שבועות","חודש"],correctAnswer:1,explanation:"אישור התוכניות בראשות מפקד הבה\"ד יתבצע לכל הפחות שבועיים טרם פתיחת מחזור ההכשרה.",source:"נוהל 1.5, עמ' 23"},
  {id:19,chapter:1,question:"כמה סוגי סיכומים עיתיים קיימים לפי נוהל 1.6?",options:["שלושה","ארבעה","חמישה","שישה"],correctAnswer:2,explanation:"קיימים חמישה סוגים של סיכומים עיתיים: יומי, שבועי, לשבועות עצימים, אמצע מחזור, וועדת הסמכות.",source:"נוהל 1.6, עמ' 25"},
  {id:20,chapter:1,question:"מי מוביל את הסיכום השבועי של הסגל?",options:["מפקד הפלוגה (מ\"פ)","מפקד הגדוד","קצין הצפה","מד\"רית המגמה"],correctAnswer:0,explanation:"סיכום שבועי של הסגל – מפגש של סגל הקורס כדי לתחקר את השבוע שחלף, מתקיים ברמה הגדודית וברמה הפלוגתית.",source:"נוהל 1.6, עמ' 26"},
  {id:21,chapter:1,question:"ועדת ההסמכות – מתי מתקיימת לכל המאוחר?",options:["לאחר מעבר 50% מהתכנים","לאחר מעבר 70% מהתכנים","לא יאוחר ממעבר 90% מהתכנים","רק בסוף ההכשרה"],correctAnswer:2,explanation:"עיתוי ביצוע דיון סטטוס הסמכות יהיה לא יאוחר ממעבר 90% תכני ההכשרה.",source:"נוהל 1.6, עמ' 27"},
  {id:22,chapter:1,question:"סיכום אמצע מחזור – מתי לכל המאוחר?",options:["לאחר מעבר 40% מהתכנים","לא יאוחר ממעבר 60% מהתכנים","לאחר מעבר 80% מהתכנים","באמצע הלוח-זמנים"],correctAnswer:1,explanation:"העיתוי המדוייק של הסיכום יקבע על-ידי המג\"ד ובכל מקרה לא יאוחר מעיתוי מעבר 60% מתכני ההכשרה.",source:"נוהל 1.6, עמ' 27"},
  {id:23,chapter:1,question:"כמה זמן מסיום ההכשרה יש להשלים את תהליך סיכום המחזור?",options:["יומיים","שלושה ימים","שבוע","שבועיים"],correctAnswer:2,explanation:"תהליך סיכום ההכשרה יושלם עד שבוע מיום סיום ההכשרה.",source:"נוהל 1.7, עמ' 29"},
  {id:24,chapter:1,question:"מה כולל סיכום מחזור ההכשרה לעניין לקחים?",options:["לקחים מקצועיים בלבד","לקחים בחתך ארבעת מימדי ההדרכה: תוכנית הכשרה, סגל, חניכים וסביבה","לקחים ארגוניים בלבד","לקחים לוגיסטיים בלבד"],correctAnswer:1,explanation:"הלקחים יתייחסו לתשומות ההכשרה ולתהליכי ההדרכה וההיערכות בחתך של ארבעת מימדי ההדרכה – תוכנית הכשרה, סגל הדרכה, חניכים וסביבת הדרכה.",source:"נוהל 1.7, עמ' 30"},
  {id:25,chapter:1,question:"כמה שנים יש לשמור תחקירי הכשרה (מצגות, דוחות, סיכומים)?",options:["שנה","שנתיים","שלוש שנים","חמש שנים"],correctAnswer:1,explanation:"המידע יישמר למשך שנתיים לפחות ויתועד באתר בה\"ד.",source:"נוהל 1.7, עמ' 31"},
  {id:26,chapter:1,question:"כמה שנים יש לשמור דוחות סופיים של הערכת הכשרה?",options:["שנה","שלוש שנים","ארבע שנים","חמש שנים"],correctAnswer:3,explanation:"הדוחות הסופיים של תהליכי הערכה ישמרו למשך 5 שנים לכל הפחות.",source:"נוהל 1.8, עמ' 34"},
  {id:27,chapter:1,question:"מה תדירות הבקרות הפנימיות ביחידת הדרכה?",options:["פעם בשנה","פעמיים בשנה","פעם במחזור","לפי שיקול דעת"],correctAnswer:2,explanation:"בקרות פנימיות יבוצעו לכלל מסגרות הבה\"ד בתדירות של פעם במחזור.",source:"נוהל 1.9, עמ' 35"},
  {id:28,chapter:1,question:"מה משך הזמן המרבי לביצוע ביקורת פנימית?",options:["שבועיים","שלושה שבועות","חודש (30 יום)","חודשיים"],correctAnswer:2,explanation:"משך זמן ביצוע הביקורת לא יעלה על חודש (30 ימים).",source:"נוהל 1.9, עמ' 35"},
  {id:29,chapter:1,question:"כמה שנים יש לשמור סיכומי ביקורות פנימיות?",options:["שנה","שנתיים","שלוש שנים","חמש שנים"],correctAnswer:3,explanation:"כלל הסיכומים של הביקורות הפנימיות יתועדו וישמרו למשך 5 שנים לכל הפחות.",source:"נוהל 1.9, עמ' 36"},
  {id:30,chapter:1,question:"מה ההבדל בין 'מידע' ל'ידע' לפי נוהל 1.10?",options:["אין הבדל, הם מילים נרדפות","מידע הוא נתון מאורגן שניתן להעביר, ידע הוא תוצר ההכרה המודעת השוכן בראש האדם","מידע הוא כמותי, ידע הוא איכותי","מידע הוא דיגיטלי, ידע הוא כתוב"],correctAnswer:1,explanation:"מידע – כל נתון בעל משמעות אשר עובד ואורגן. ידע – תוצר ההכרה המודעת של האדם בעובדות ובתופעות, שוכן בראשו.",source:"נוהל 1.10, עמ' 37"},
  {id:31,chapter:2,question:"מהי ההחלטה על פיתוח הכשרה חדשה – מי מחליט?",options:["מפקד הבהד עצמאית","ההחלטה היא זרועית/מטכ\"לית והביצוע הוא על-ידי הבהד","מפקד הגדוד","ענף הדרכה בלבד"],correctAnswer:1,explanation:"ההחלטה על הצורך בהכשרה חדשה הינה החלטה זרועית/מטכ\"לית, והביצוע הינו על-ידי הבה\"ד.",source:"נוהל 2.1, עמ' 43"},
  {id:32,chapter:2,question:"מה הם שני המודלים הנפוצים לפיתוח הדרכה?",options:["מודל ADDIE ומודל Bloom","מודל אלפא ומודל תל\"ם","מודל ISO ומודל קירקפטריק","מודל Agile ומודל Waterfall"],correctAnswer:1,explanation:"השכיחים מבין המודלים הם מודל אלפ\"א ומודל תל\"ם.",source:"נוהל 2.1, עמ' 43"},
  {id:33,chapter:2,question:"מהו 'תיק יסוד' לפי ההגדרה?",options:["תיק אישי של הצוער","מסמך מחייב לכל קורס/השתלמות המתעד הגדרות, החלטות, נתונים ומשאבים","תיק המכיל ציוני מבחנים","לוח הזמנים השנתי"],correctAnswer:1,explanation:"תיק יסוד לקורס הוא מסמך מחייב, המהווה בסיס לביצוע קורס או השתלמות ומתעד בתוכו את ההגדרות, ההחלטות, הנתונים והמשאבים.",source:"נוהל 2.2, עמ' 46"},
  {id:34,chapter:2,question:"מהי ה'הסמכה' לפי הגדרת התקן?",options:["מבחן בכתב","מתן אישור רשמי לבעל תפקיד שסיים קורס מתאים, כי הוכשר למלא תפקיד","אישור משרד הביטחון","קבלת דרגה"],correctAnswer:1,explanation:"הסמכה – מתן אישור רשמי לבעל תפקיד שסיים קורס מתאים, כי הוכשר למלא תפקיד ולמלא את המטלות הצפויות לו בתפקידו.",source:"נוהל 2.2, עמ' 46"},
  {id:35,chapter:2,question:"כל כמה שנים נדרש תיקוף תיק יסוד?",options:["כל שנה","כל שלוש שנים","כל חמש שנים","כל שבע שנים"],correctAnswer:2,explanation:"תיקוף תיק היסוד נדרש אחת לחמש שנים.",source:"נוהל 2.2, עמ' 47"},
  {id:36,chapter:2,question:"מי מאשר תיק יסוד להכשרה חדשה ראשון?",options:["ענף הדרכה הזרועי ראשון","מפקד הבהד יאשר כל תיק יסוד להכשרה חדשה","מפקד הגדוד","מפקד הפלוגה"],correctAnswer:1,explanation:"מפקד הבה\"ד יאשר כל תיק יסוד להכשרה חדשה.",source:"נוהל 2.2, עמ' 48"},
  {id:37,chapter:2,question:"מה קורה לתיק יסוד בהכשרת 'גפן' בסיום סבב האישורים הזרועי?",options:["מאושר ע\"י מפקד הבהד","מאושר ע\"י קחצ\"ר","מאושר ע\"י מטכ\"ל","אין צורך באישור נוסף"],correctAnswer:1,explanation:"בהכשרת גפן, בסיום סבב האישור הזרועי, יאשר קחצ\"ר את תיק היסוד.",source:"נוהל 2.2, עמ' 48"},
  {id:38,chapter:2,question:"כמה שנים יש לשמור תהליך פיתוח הכשרה חדשה?",options:["שנתיים","שלוש שנים","ארבע שנים","חמש שנים"],correctAnswer:3,explanation:"תקופת שימור הידע הינה למשך 5 שנים לכל הפחות מיום פתיחת ההכשרה הראשונה.",source:"נוהל 2.1, עמ' 45"},
  {id:39,chapter:2,question:"מה ההבדל בין 'הערכה מסכמת' ל'הערכה מעצבת'?",options:["אין הבדל","מסכמת מתקיימת בסוף ולמטרת קבלת החלטות; מעצבת מתקיימת במהלך לצורך שיפור","מסכמת ממוחשבת, מעצבת ידנית","מסכמת ע\"י מפקד, מעצבת ע\"י הצוער"],correctAnswer:1,explanation:"הערכה מסכמת – מתקיימת בסוף תהליך הדרכתי כלשהו ומשמשת לקבלת החלטות. הערכה מעצבת – מתבצעת במהלך ההדרכה לצורך למידה ושיפור.",source:"נוהל 2.3, עמ' 50"},
  {id:40,chapter:2,question:"מהו 'עץ הערכה' בהכשרה?",options:["תרשים ארגוני של הכשרה","כלי המשקף את רמת כשירות הצוער בכל מרכיבי תפקידו בסוף ההכשרה","רשימת מבחנים","לוח זמנים להכשרה"],correctAnswer:1,explanation:"עץ הערכה הוא כלי המשקף את רמת כשירות הצוער בכל אחד ממרכיבי תפקידיו בסוף ההכשרה. מפרט ציוני כלל מצבי המבחן כולל תנאי הסמכה.",source:"נוהל 2.3, עמ' 51"},
  {id:41,chapter:2,question:"מה האחוז המרבי של מבחנים עיוניים מסך המבחנים המסמיכים בהכשרה?",options:["20%","30%","40%","50%"],correctAnswer:1,explanation:"בכל מקרה המבחנים העיוניים לא יעלו על 30% מסך כלל המבחנים המסמיכים בהכשרה.",source:"נוהל 2.3, עמ' 51"},
  {id:42,chapter:2,question:"מה כולל 'מתאר מבחן' לכל מבחן עיוני?",options:["שאלות המבחן עצמן","הנושאים המוערכים, היקף שאלות בכל נושא ורמת ידע, ואופן חלוקת הציונים","שם הנבחנים","לוח הזמנים למבחן"],correctAnswer:1,explanation:"לכל מבחן עיוני יהיה טופס 'מתאר מבחן' אשר מגדיר את הנושאים המוערכים, היקף השאלות בכל נושא ורמת ידע, ואופן חלוקת הציונים וציון הסף.",source:"נוהל 2.3, עמ' 52"},
  {id:43,chapter:2,question:"כמה מועדי מבחן ניתנים לצוער כברירת מחדל?",options:["מועד אחד","שני מועדים (א' וב')","שלושה מועדים","ארבעה מועדים"],correctAnswer:1,explanation:"לכל צוער יינתנו שני מועדים לביצוע המבחן – מועד א' ומועד ב'.",source:"נוהל 2.3, עמ' 54"},
  {id:44,chapter:2,question:"מה חלוקת הציון הסופי כשצוער ניגש למועד א' ומועד ב'?",options:["50% מועד א', 50% מועד ב'","30% מועד א', 70% מועד ב'","20% מועד א', 80% מועד ב'","10% מועד א', 90% מועד ב'"],correctAnswer:2,explanation:"חישוב הציון הסופי: 20% מועד א' ו-80% מועד ב'.",source:"נוהל 2.3, עמ' 54"},
  {id:45,chapter:2,question:"מה חלוקת הציון כשצוער ניגש לשלושה מועדים?",options:["שליש שווה לכל מועד","10% מועד א', 10% מועד ב', 80% מועד ג'","20% מועד א', 20% מועד ב', 60% מועד ג'","5%, 15%, 80%"],correctAnswer:1,explanation:"במידה וצוער ביצע מועד ג', אז החלוקה תהיה 10% מועד א', 10% מועד ב', 80% מועד ג'.",source:"נוהל 2.3, עמ' 54"},
  {id:46,chapter:2,question:"מתי חייב לפתוח תהליך 'צוער מתקשה'?",options:["אחרי כישלון במבחן אחד","אחרי כישלון בשני מבחנים","אחרי כישלון בשלושה מבחנים שונים","לאחר החלטת מפקד בלבד"],correctAnswer:2,explanation:"צוער שנכשל בשלושה מועדים שונים, יש לפתוח עבורו תהליך צוער מתקשה.",source:"נוהל 2.3, עמ' 54"},
  {id:47,chapter:2,question:"מה ציון הסף שמחייב ניתוח סטטיסטי של תוצאות המבחן?",options:["למעלה מ-30% נכשלים","למעלה מ-40% נכשלים","למעלה מ-50% נכשלים","למעלה מ-60% נכשלים"],correctAnswer:2,explanation:"במקרים הבאים יש לבצע תחקור לתוצאות המבחן: למעלה מ-50% נכשלים.",source:"נוהל 2.3, עמ' 54"},
  {id:48,chapter:2,question:"מהו 'תיק מדריך' לפי ההגדרה?",options:["ציוני הצוערים בלבד","תיק הכולל את התוכן המקצועי והפעולות ההדרכתיות המרכיבות שיעור/פעילות מעשית","לוח שיעורים","תיק אישי של המדריך"],correctAnswer:1,explanation:"תיק מדריך הוא תיק הכולל את התוכן המקצועי והפעולות ההדרכתיות המרכיבות שיעור פרונטלי או פעילות בעלת מרכיבים מעשיים.",source:"נוהל 2.4, עמ' 55"},
  {id:49,chapter:2,question:"כל כמה שנים נדרש תיקוף תיק מדריך?",options:["כל שנה","כל שנתיים","כל שלוש שנים","כל חמש שנים"],correctAnswer:2,explanation:"תיק מדריך נדרש לתיקוף אחת לשלוש שנים.",source:"נוהל 2.4, עמ' 57"},
  {id:50,chapter:2,question:"מה כולל כל תיק מדריך לפי נוהל 2.4?",options:["מערך שיעור בלבד","דף אישורים בלבד","דף אישורים, מבואות, תיק תוכן, מערך שיעור ותכולת הדרכה","ציוני הצוערים ומסקנות"],correctAnswer:2,explanation:"כל תיק מדריך יכלול: דף אישורים, מבואות, תיק תוכן, מערך שיעור ותכולת ההדרכה הנלוות להעברת השיעור.",source:"נוהל 2.4, עמ' 56-57"},
  {id:51,chapter:2,question:"מי מאשר את תיק המדריך מבחינת תוכן תורתי?",options:["מפקד הפלוגה","אישור תורתי ממפקדת החיל הרלוונטי או מומחה תוכן שהוסמך על-ידי החיל","מפקד הגדוד","קצין הדרכה"],correctAnswer:1,explanation:"כל תיק מדריך יאושר על-ידי אישור תורתי ממפקדת החיל הרלוונטי או מומחה תוכן שהוסמך על-ידי החיל.",source:"נוהל 2.4, עמ' 57"},
  {id:52,chapter:2,question:"מה 'מצב מבחן' לפי הגדרת נוהל 2.3?",options:["מבחן כתוב פורמלי","תרגיל מרכזי בהכשרה המתרגל את הצוער בביצוע משימה על כל שלביה","ביקורת חיצונית","מבחן גופני"],correctAnswer:1,explanation:"מצב מבחן הוא תרגיל מרכזי בהכשרה (מודל אלפ\"א) אשר מתרגל את הצוער בביצוע משימה על כל שלביה.",source:"נוהל 2.3, עמ' 51"},
  {id:53,chapter:2,question:"מתי חובה לבצע ניתוח סטטיסטי למבחן?",options:["רק למבחנים חדשים","עבור כל מבחן חדש, וכן כאשר מעל 50% נכשלים או כשמנעד הציונים נמוך מ-10 נקודות","רק למבחנים מסמיכים","פעם בשנה"],correctAnswer:1,explanation:"עבור כל מבחן חדש יבוצע ניתוח סטטיסטי, וכן כאשר למעלה מ-50% נכשלים, או כאשר מנעד ציונים נמוך (10 נקודות בין הגבוה לנמוך).",source:"נוהל 2.3, עמ' 52-54"},
  {id:54,chapter:2,question:"מה כוללת 'הכשרה' לפי הגדרת נוהל 2.2?",options:["מסגרת ציבורית ללימודים","תהליך למידה שבאמצעותו מקנים לחיילים ידע, מיומנויות ועמדות החסרים להם לביצוע תפקידם","כל פעילות צבאית","תדריך פורמלי"],correctAnswer:1,explanation:"הכשרה – תהליך למידה באמצעותו מקנים לחיילים, מפקדים ומסגרות, ידע, מיומנויות ועמדות החסרים להם וההכרחיים לביצוע תפקידם.",source:"נוהל 2.2, עמ' 46"},
  {id:55,chapter:2,question:"מה ההבדל בין 'קורס' ל'השתלמות'?",options:["אין הבדל","קורס הוא הכשרה מסמיכה, השתלמות היא הכשרה שאינה מסמיכה","קורס הוא ארוך, השתלמות קצרה","קורס הוא חובה, השתלמות רשות"],correctAnswer:1,explanation:"קורס – לימודים בארגון לשם ביצוע הכשרה מסמיכה. השתלמות – לימודים בארגון לשם ביצוע הכשרה לא מסמיכה.",source:"נוהל 2.1, עמ' 43"},
  {id:56,chapter:2,question:"מה 'יחידת לימוד' לפי הגדרת נוהל 2.4?",options:["יחידה ארגונית בצבא","פעילות הדרכתית בעלת גבולות תוכן (התחלה, אמצע וסוף), מתוחמת בזמן ומאורגנת להשגת מטרות למידה","שיעור אחד בלבד","יחידת מדידה"],correctAnswer:1,explanation:"יחידת לימוד – פעילות הדרכתית בעלת גבולות של תוכן (התחלה, אמצע וסוף), המתוחמת בזמן ומאורגנת להשגת מטרה/מטרות למידה מסוימות.",source:"נוהל 2.4, עמ' 55"},
  {id:57,chapter:2,question:"מה מגדיר 'כשירות' בהקשר של הכשרה?",options:["ידע תיאורטי בלבד","יכולת ביצוע בתחום פעילות מסוים הדרושה כדי למלא משימה כלשהי","דרגת קצין","ממוצע ציונים"],correctAnswer:1,explanation:"כשירות – יכולת ביצוע בתחום פעילות מסוים הדרושה כדי למלא משימה כלשהי. כשירות נרכשת במסגרת תהליכי ההכשרה ומשופרת במסגרת אימונים.",source:"נוהל 2.2, עמ' 46"},
  {id:58,chapter:2,question:"מהו 'מבחן מעשי מפורק'?",options:["מבחן שנפרק לחלקים קטנים","ביצוע פעולה אחת או כמה פעולות בדידות ללא הקשר ותרחיש","מבחן בשטח פתוח","מבחן בלי ציון"],correctAnswer:1,explanation:"מבחן מעשי מפורק ('בוחן מעשי מפורק' או 'מבחן תחנות') – ביצוע פעולה אחת או מספר פעולות בדידות ללא הקשר ותרחיש.",source:"נוהל 2.3, עמ' 51"},
  {id:59,chapter:2,question:"מתי חובה לעדכן תיק מדריך בנוסף לתיקוף התקופתי?",options:["רק בפיתוח הכשרה חדשה","בפיתוח הכשרה חדשה, ברה-פיתוח של קורס קיים, ובעדכון שיטת לימוד/תו\"ל","אחת לשנה בכל מקרה","רק כשיש שינוי בתוכן"],correctAnswer:1,explanation:"כתיבה או תיקוף של תיק מדריך נדרש: בפיתוח הכשרה חדשה, ברה-פיתוח של קורס קיים, בעדכון שיטת לימוד/תו\"ל, ואחת לשלוש שנים.",source:"נוהל 2.4, עמ' 57"},
  {id:60,chapter:2,question:"מה כולל 'ניתוח התפקיד' שנדרש טרם פיתוח הכשרה חדשה?",options:["תיאור כללי בלבד","ניתוח מדויק של מצבי התפקוד של בעל התפקיד, תחומי אחריותו ותהליך העבודה שלו","רשימת שמות","לוח שיעורים"],correctAnswer:1,explanation:"ניתוח התפקיד – ניתוח מדויק של מצבי התפקוד של בעל התפקיד, תחומי אחריותו, תהליך העבודה שלו ועוד.",source:"נוהל 2.1, עמ' 44"},
  {id:61,chapter:3,question:"מהו 'סגל מפקדים' לפי ההגדרה?",options:["קצינים בלבד","בעלי תפקיד העוסקים בפיקוד על הצוערים, הדרכתם, תרגולם, בחינתם והערכתם","מדריכים מקצועיים","גורמי לוגיסטיקה"],correctAnswer:1,explanation:"סגל מפקדים – בע\"ת שעוסק בפיקוד על הצוערים בהכשרה, הדרכתם, תרגולם, בחינתם והערכתם. על סגל המפקדים נמנים מפק\"ץ, מ\"פ, סמג\"ד, מג\"ד וקה\"דית.",source:"נוהל 3.1, עמ' 58"},
  {id:62,chapter:3,question:"מהם תחומי אחריות מפקד הגדוד בהכשרה?",options:["רק לוגיסטיקה ותאום","ביצוע הכשרה איכותית, אישורי תוכניות, סיכומים, ועדת הסמכות וחניכת מ\"פים","רק מבחנים ומדדים","ניהול תקציב בלבד"],correctAnswer:1,explanation:"תחומי אחריות המג\"ד כוללים: ביצוע הכשרה אפקטיבית ויעילה, ביצוע אישורי תוכניות, סיכומי אמצע וסוף, קיום פורום הסמכות, חניכה וליווי מ\"פים ועוד.",source:"נוהל 3.1, עמ' 59"},
  {id:63,chapter:3,question:"מה מספר המחזורים לאיש סגל בהכשרות לוחמים?",options:["מחזור אחד","2 מחזורים","3 מחזורים","4 מחזורים"],correctAnswer:1,explanation:"כל איש סגל יבצע תפקיד בין 2 ל-4 מחזורים. לוחמים – 2, מטה – 4.",source:"נוהל 3.2, עמ' 69"},
  {id:64,chapter:3,question:"מה היחס הנדרש בין אנשי סגל ותיקים לחדשים?",options:["50:50","40:60 (ותיקים:חדשים)","30:70 (ותיקים:חדשים)","20:80 (ותיקים:חדשים)"],correctAnswer:2,explanation:"יש לשאוף לתמהיל של אנשי סגל בעלי ניסיון תפקיד לעומת אנשי סגל ללא ניסיון ביחס של 30:70 בהתאמה.",source:"נוהל 3.2, עמ' 69"},
  {id:65,chapter:3,question:"מתי מותר להחליף אנשי סגל?",options:["בכל עת","רק בסיום מחזור (אלא בחריג מאושר ממפקד הבהד)","רק בתחילת שנה","אחרי מינימום 3 חודשים"],correctAnswer:1,explanation:"החלפת אנשי סגל תתקיים אך ורק בסיום מחזור ולא במהלכו אלא באישור חריג של מפקד בה\"ד.",source:"נוהל 3.2, עמ' 69"},
  {id:66,chapter:3,question:"כמה אחוז מהצוערים יסומנו כ'מאותרים להדרכה'?",options:["5%-10%","10%-20%","15%-30%","20%-40%"],correctAnswer:2,explanation:"בהכשרות יש לסמן בין 15% ל-30% צוערים 'מאותרים להדרכה'.",source:"נוהל 3.2, עמ' 70"},
  {id:67,chapter:3,question:"מאיזה שליש ניתן לאתר מאותרי הדרכה?",options:["מהשליש התחתון בלבד","מהשליש העליון או האמצעי, אך לא מהתחתון","מכל שליש שווה בשווה","אין הגבלה"],correctAnswer:1,explanation:"בהכשרות בהם קיים דירוג שלישים, יהיו המאותרים מהשליש העליון או האמצעי בדירוג אך לא מהשליש התחתון.",source:"נוהל 3.2, עמ' 70"},
  {id:68,chapter:3,question:"כמה מהמאותרים צריכים להוות מהפוטנציאל לסגלי ההכשרה בהכשרות פיקוד?",options:["לפחות 50%","לפחות 60%","לפחות 70%","לפחות 80%"],correctAnswer:3,explanation:"אוכלוסיית המאותרים תהווה לא פחות מ-80% מכלל הפוטנציאל לסגלי ההכשרה להכשרות הפיקוד.",source:"נוהל 3.2, עמ' 71"},
  {id:69,chapter:3,question:"מה כוללת 'הכנת סגל' לפי ההגדרה?",options:["רק לימוד תו\"ל","תהליך של בניית סגל כצוות עבודה לקראת העברת הכשרה ספציפית, עם סגל ספציפי","ביקורת חיצונית של הגדוד","מסדר רשמי לפתיחת מחזור"],correctAnswer:1,explanation:"הכנת סגל – תהליך של בניית סגל (כצוות עבודה) לקראת העברת הכשרה, ממוקדת לתוכנית הכשרה ספציפית, עם סגל ספציפי, והגדרות תפקידים ספציפיים.",source:"נוהל 3.3, עמ' 73"},
  {id:70,chapter:3,question:"מהם ארבעת הצירים של הכנת הסגל?",options:["לוגיסטי, מקצועי, פיקודי, ובטיחותי","פיקודי, מקצועי, הדרכתי, ועבודת הסגל","חינוכי, מקצועי, גופני, ומנהלתי","תיאורטי, מעשי, ערכי, וחברתי"],correctAnswer:1,explanation:"הכנת הסגל תיבנה בחלוקה לארבעה צירים: ציר פיקודי, ציר מקצועי, ציר הדרכתי, וציר עבודת הסגל.",source:"נוהל 3.3, עמ' 74-75"},
  {id:71,chapter:3,question:"מה אחוז הנוכחות הנדרש מאיש סגל בהכנת הסגל?",options:["60%","70%","80%","90%"],correctAnswer:2,explanation:"איש סגל נדרש לנכוח ב-80% ממופעי הכנת הסגל כולל מופעי הכנות הסגל תוך כדי מחזור.",source:"נוהל 3.3, עמ' 76"},
  {id:72,chapter:3,question:"מה משך הכנת הסגל לפי הכלל הכללי?",options:["10% מזמן ההכשרה","20% מזמן ההכשרה","30% מזמן ההכשרה","25% מזמן ההכשרה"],correctAnswer:1,explanation:"ככלל, משך הכנת הסגל יהיה 20% מזמן ההכשרה טרם ההכשרה.",source:"נוהל 3.3, עמ' 76"},
  {id:73,chapter:3,question:"מה ציון הסף לבוחן הרמה המקצועי עבור סגל?",options:["60","70","75","80"],correctAnswer:3,explanation:"ציון הסף לבוחן הרמה המקצועי הינו 80.",source:"נוהל 3.4, עמ' 80"},
  {id:74,chapter:3,question:"כמה פעמים במחזור מקיים המפקד 'מופע חניכה' (משוב) על איש הסגל?",options:["פעם אחת","פעמיים","שלוש פעמים","ארבע פעמים"],correctAnswer:1,explanation:"פעמיים במחזור הכשרה יבצע המפקד הממונה משוב על איש הסגל, תצפית סדורה במופע פורמאלי.",source:"נוהל 3.4, עמ' 81"},
  {id:75,chapter:3,question:"מהי 'חניכה' לפי הגדרת התקן?",options:["הוראה פרונטלית","תהליך למידה המבוסס על קשר מתמשך בו מסייע החונך לנחנך ללמוד מהתנסויות","מבחן שנתי","ביקורת חיצונית"],correctAnswer:1,explanation:"חניכה – תהליך למידה, המבוסס על קשר מתמשך בו מסייע החונך לנחנך ללמוד מההתנסויות שהוא מבצע.",source:"נוהל 3.4, עמ' 79"},
  {id:76,chapter:3,question:"מה משך קדנציית מ\"פ בהכשרות לוחמים?",options:["חצי שנה","שנה","שנתיים","שלוש שנים"],correctAnswer:1,explanation:"מפקדים בדרג מ\"פ ומקביליו יבצעו תפקיד של שנה (לוחמים) ושנה (תומכ\"ל).",source:"נוהל 3.6, עמ' 84"},
  {id:77,chapter:3,question:"מה משך קדנציה מינימלי למגד בהכשרות?",options:["שנה","שנתיים לכל הפחות","שלוש שנים","לפי שיקול מפקד הבהד"],correctAnswer:1,explanation:"מפקדים בדרג המג\"ד יבצעו תפקיד של שנתיים לכל הפחות.",source:"נוהל 3.6, עמ' 84"},
  {id:78,chapter:3,question:"מתי מפקד יוצא חייב לכתוב 'מסמך אחרית'?",options:["ביום הפרידה","חודש טרם סיום התפקיד המתוכנן","שבועיים לפני","רק לבקשת הממונה"],correctAnswer:1,explanation:"חודש טרם סיום התפקיד המתוכנן של מפקד בכיר, הנ\"ל יכתוב מסמך סיום תפקיד 'מסמך אחרית'.",source:"נוהל 3.6, עמ' 85"},
  {id:79,chapter:3,question:"מה מסמך 'בראשית'?",options:["מסמך מינוי לתפקיד","מסמך שכותב מפקד נכנס כחודש מתחילת תפקידו – אבחון ויעדים אישיים","דוח שנתי","תוכנית עבודה"],correctAnswer:1,explanation:"כחודש מתחילת תפקידו של כל מפקד עליו לכתוב מסמך 'בראשית' – אבחון היחידה לאחר תהליך הכניסה לתפקיד וכן יעדים אישיים.",source:"נוהל 3.6, עמ' 86"},
  {id:80,chapter:3,question:"כמה שבועות לפני כניסה לתפקיד מקבל מפקד בכיר נכנס את תיק הכניסה לתפקיד?",options:["שבוע","שבועיים","שלושה שבועות","חודש"],correctAnswer:2,explanation:"כל מפקד בכיר נכנס יקבל תיק כניסה לתפקיד שלושה שבועות טרם כניסתו לתפקיד.",source:"נוהל 3.6, עמ' 85"},
  {id:81,chapter:3,question:"כמה זמן נמשכת חפיפת מגד/רען לכל הפחות?",options:["שבוע","שבועיים","שלושה שבועות","חודש"],correctAnswer:1,explanation:"חפיפת מג\"דים/רע\"נים ומעלה תימשך שבועיים לכל הפחות.",source:"נוהל 3.6, עמ' 85"},
  {id:82,chapter:3,question:"מה כולל 'תיק כניסה לתפקיד' (תיק חפיפה)?",options:["לוח שיעורים בלבד","תיקי יסוד, סיכומי 2 מחזורים אחרונים, שבצ\"ק מפקדים ומסמך סיום תפקיד של המפקד היוצא","תיק אישי","פקודות כלליות"],correctAnswer:1,explanation:"תיק כניסה לתפקיד יכלול: תיקי היסוד להכשרות, סיכומי שני מחזורי ההכשרה האחרונים, שבצ\"ק המפקדים, מסמך סיכום תפקיד של המפקד היוצא, וסוגיות פתוחות.",source:"נוהל 3.6, עמ' 85"},
  {id:83,chapter:3,question:"כמה פעמים בשנה מתכנס פורום הדרכה בכיר?",options:["פעמיים","שלוש פעמים","ארבע פעמים","חמש פעמים"],correctAnswer:1,explanation:"פורום בכיר יתכנס 3 פעמים בשנה.",source:"נוהל 3.8, עמ' 91"},
  {id:84,chapter:3,question:"כמה פעמים בשנה מתכנס פורום הדרכה מורחב?",options:["פעם אחת","פעמיים","שלוש פעמים","ארבע פעמים"],correctAnswer:1,explanation:"פורום מורחב יתכנס פעמיים בשנה.",source:"נוהל 3.8, עמ' 91"},
  {id:85,chapter:3,question:"מי מוביל את פורום ההדרכה הבהדי?",options:["מפקד הגדוד","מפקד הגפה","קצין אגם","מד\"רית מגמה"],correctAnswer:1,explanation:"מוביל הפורומים ביחידה הינו מפקד הגפ\"ה ובאחריותו ניהול עבודת המטה לרבות כתיבת הפק\"א והסיכום.",source:"נוהל 3.8, עמ' 92"},
  {id:86,chapter:3,question:"מה מטרת פורום ההדרכה הבהדי?",options:["קיום ישיבות שבועיות","קידום תהליכי הדרכה המושפעים משינויים ושיפור וטיוב ההכשרות","ביקורת פנימית","תיאום לוחות זמנים"],correctAnswer:1,explanation:"פורום הדרכה בה\"די נועד לקדם תהליכי הדרכה המושפעים מהשינויים ותכליתו הינו שיפור וטיוב ההכשרות בבה\"ד.",source:"נוהל 3.8, עמ' 91"},
  {id:87,chapter:3,question:"מי מחליט בועדת הרחקת מ\"פ מתפקידו?",options:["מפקד הבהד בלבד","מפקד החיל הרלוונטי / מפקד הבהד המקבל סמכות מהחיל","מפקד הגדוד","ועדת קצינים"],correctAnswer:1,explanation:"סמכות הרחקת מ\"פ – מפקד החיל הרלוונטי / מפקד הבה\"ד המקבל את הסמכות ממפקד החיל.",source:"נוהל 3.7, עמ' 88"},
  {id:88,chapter:3,question:"מה 'הדחה מתפקיד' לפי הגדרת נוהל 3.7?",options:["העברה לתפקיד אחר","הפסקת תפקידו של מדריך/מפקד כתגובה על התנהגותו והוצאתו מהמסגרת","ירידה בדרגה","השעיה זמנית"],correctAnswer:1,explanation:"הדחה מתפקיד – הפסקת תפקידו של מדריך/מפקד כתגובה על התנהגותו והוצאתו מהמסגרת.",source:"נוהל 3.7, עמ' 88"},
  {id:89,chapter:3,question:"מהי הגדרת 'הכשרת הדרכה' ומתי מבצעים אותה?",options:["מבחן שנתי","הכשרה מקצועית בבית הספר להדרכה לבעלי תפקידים, עד שלושה חודשים מכניסתם לתפקידם","הכנת סגל בלבד","קורס פנימי בגדוד"],correctAnswer:1,explanation:"ההכשרה לתפקיד תבוצע עד שלושה חודשים מכניסת בעל התפקיד לתפקידו.",source:"נוהל 3.5, עמ' 83"},
  {id:90,chapter:3,question:"כמה שבועות לפני תהליך המיון יש להפיץ פקודה לאיתור מועמדים לסגלי הכשרות?",options:["חודש לפני","כשלושה שבועות לפני תהליך המיון","שבוע לפני","יומיים לפני"],correctAnswer:1,explanation:"כשלושה שבועות טרם תהליך המיון, יש להפיץ פקודה בדבר איתור מועמדים לסגלי הכשרות.",source:"נוהל 3.2, עמ' 70"},
  {id:91,chapter:4,question:"מהו 'צוער מתקשה' לפי הגדרת התקן?",options:["צוער שמתחרט ורוצה לעזוב","צוער שאינו עומד בתנאי הסף להכשרה בהיבט הלימודי או הנורמטיבי-ערכי","צוער עם בעיות בריאותיות","צוער שנעדר"],correctAnswer:1,explanation:"צוער מתקשה – צוער שאינו עומד בתנאי הסף להכשרה, כפי שמפורט בתיק היסוד, בהיבט הלימודי או בהיבט הנורמטיבי והערכי.",source:"נוהל 4.1, עמ' 93"},
  {id:92,chapter:4,question:"עד מתי יש לגבש רשימה ראשונית של צוערים מתקשים?",options:["עד תום השבוע הראשון","עד תום שבועיים הראשונים","עד אמצע הקורס","רק לאחר כישלון במבחן"],correctAnswer:1,explanation:"עד תום השבועיים הראשונים להכשרה, תגובש רשימה ראשונית של הצוערים אשר עשויים להתקשות.",source:"נוהל 4.1, עמ' 94"},
  {id:93,chapter:4,question:"מי מנהל את רשימת הצוערים המתקשים?",options:["מפקד הבהד","מפקד הפלוגה","קצין הסגל","מפקד הגדוד"],correctAnswer:1,explanation:"רשימת הצוערים המתקשים תנוהל ע\"י מפקד הפלוגה.",source:"נוהל 4.1, עמ' 95"},
  {id:94,chapter:4,question:"מה כוללת תוכנית הקידום האישית (צפא) לצוער מתקשה?",options:["ציונים בלבד","פירוט התחומים בהם מתבטא הקושי, יעדים אישיים, ודרכי פעולה לקידומו","לוח זמנים לסיום הקורס","המלצה להרחקה"],correctAnswer:1,explanation:"התוכנית תכלול: פירוט התחומים בהם מתבטא הקושי, הגדרת יעדים אישיים לצוער, ודרכי הפעולה לקידום הצוער.",source:"נוהל 4.1, עמ' 94"},
  {id:95,chapter:4,question:"כמה תנאים מקדימים יש לוועדת הערכה לצוער?",options:["אין תנאים מקדימים","ביצוע תהליך שיקוף מצבו ומתן כלים ותנאים לשיפור (לפי נוהל 4.1)","הגשת עתירה כתובה","אישור רופא"],correctAnswer:1,explanation:"טרם העלאת הצוער לוועדת הערכה יש לבצע עם הצוער תהליך של שיקוף מצבו ושאכן ניתנו לו הכלים והתנאים לבצע תהליך שיפור.",source:"נוהל 4.2, עמ' 96"},
  {id:96,chapter:4,question:"מה עיתוי העלאת צוער לוועדת הערכה?",options:["בכל עת","לפני מעבר 50% מהתכנים","לפני מעבר 80% מתכני ההכשרה המחייבים","רק בסוף"],correctAnswer:2,explanation:"עיתוי להעלאת צוער לוועדה יהיה לפני שעבר 80% מתכני ההכשרה המחייבים (עד 10 ימים מסיום ההכשרה).",source:"נוהל 4.2, עמ' 96"},
  {id:97,chapter:4,question:"כמה פעמים מתקיימות ועדות הערכה לצוערים במחזור?",options:["פעם אחת","פעמיים – ועדות אמצע וועדות סוף","שלוש פעמים","לפי הצורך"],correctAnswer:1,explanation:"ועדת הערכה מתקיימת פעמיים במחזור – ועדות אמצע וועדות סוף.",source:"נוהל 4.2, עמ' 97"},
  {id:98,chapter:4,question:"כמה ימים לפני הוועדה חייב הצוער לקבל התראה?",options:["יום אחד","יומיים","שלושה ימים","שבוע"],correctAnswer:2,explanation:"צוער העולה לוועדת הערכה יקבל התראה ממפקדו הישיר של שלושה ימים טרם מועד הוועדה.",source:"נוהל 4.2, עמ' 98"},
  {id:99,chapter:4,question:"מי קובע בוועדה הראשונה (ועדת מפקץ)?",options:["מפקד הבהד","מפקץ קובע אם הצוער עולה לוועדה נוספת אצל המ\"פ או ממשיך בקורס","מפקד הגדוד","יועצת הבהד"],correctAnswer:1,explanation:"ועדה ראשונה – מפק\"ץ, קובע אם עולה ועדה נוספת אצל המ\"פ או ממשיך בקורס.",source:"נוהל 4.2, עמ' 98"},
  {id:100,chapter:4,question:"מה ההבדל בין 'מורחק' ל'מודח' בוועדת הבהד?",options:["אין הבדל","מורחק יכול לחזור במחזור הבא, מודח לא יכול לחזור בכלל","מורחק לא יכול לחזור, מודח יכול לחזור","מורחק עוזב מרצון, מודח בכפיה"],correctAnswer:1,explanation:"מפקד הבה\"ד מחליט אם הצוער ממשיך בקורס, מורחק (לא מסיים המחזור, אך יכול לחזור במחזור הבא) או מודח (לא יכול לחזור בכלל להכשרה).",source:"נוהל 4.2, עמ' 97"},
  {id:101,chapter:4,question:"מה ציון הסף לתעודת הצטיינות לצוער מצטיין?",options:["70","75","80","85"],correctAnswer:2,explanation:"תעודות הצטיינות יינתנו למי שהציון היחסי נמצא בקרב עשרת האחוזים הראשונים ואינו נופל מציון 80.",source:"נוהל 4.3, עמ' 99"},
  {id:102,chapter:4,question:"מה ההבדל בין 'צוער מצטיין' ל'צוער למופת'?",options:["אין הבדל","מצטיין מחייב ציון 80+ ב-10% העליון, למופת מחייב עמידה בתבחינים התנהגותיים בלבד","מצטיין הוא לוחמי, למופת הוא מטה","מצטיין נבחר ע\"י הצוערים, למופת ע\"י הסגל"],correctAnswer:1,explanation:"תעודות הצטיינות – ציון 80+ ב-10% העליון. תעודות ציון למופת – למי שעמדו בכל התבחינים ההתנהגותיים והערכיים שהוגדרו.",source:"נוהל 4.3, עמ' 99"},
  {id:103,chapter:4,question:"מה ציון הסף המינימלי לצוער מאותר הדרכה?",options:["70","75","80","85"],correctAnswer:2,explanation:"צוער עם ציון סופי העומד על לא מתחת ל-80 יכול להיות מאותר הדרכה.",source:"נוהל 4.3ב', עמ' 101"},
  {id:104,chapter:4,question:"כמה מאותרי הדרכה בוחר כל מפקץ בהכשרה?",options:["אחד","כשניים","שלושה","ארבעה"],correctAnswer:1,explanation:"בכל הכשרה כל מפק\"ץ יבחר כ-2 צוערים מאותרי הדרכה.",source:"נוהל 4.3ב', עמ' 101"},
  {id:105,chapter:4,question:"כמה שנים יש לשמור מסמכי בחירת צוער מאותר הדרכה?",options:["שנה","שנה וחצי","שנתיים","שלוש שנים"],correctAnswer:1,explanation:"תהליך בחירת צוער מאותר הדרכה תתועד ותישמר למשך שנה וחצי.",source:"נוהל 4.3ב', עמ' 102"},
  {id:106,chapter:4,question:"כיצד מנוהל התיק האישי לצוער?",options:["בתיק נייר אישי","במערכת הקמפוס הדיגיטלי","בקבצי אקסל","ע\"י קצין הסגל"],correctAnswer:1,explanation:"תיק אישי לצוער ינוהל במערכת הקמפוס.",source:"נוהל 4.4, עמ' 103"},
  {id:107,chapter:4,question:"מה מנוהל בתיק האישי של הצוער?",options:["ציוני מבחנים בלבד","סיכום קליטה, ציוני הסמכה, משובי התנסויות, תוכנית חניכה, אירועים חריגים ועוד","פרטים אישיים בלבד","תיק רפואי"],correctAnswer:1,explanation:"התיק כולל: סיכום דף קליטה, סטטוס ביצוע וציוני מבחנים, משובי התנסויות ותרגילים, תוכנית החניכה, אירועים אישיים חריגים ועוד.",source:"נוהל 4.4, עמ' 103-104"},
  {id:108,chapter:4,question:"כמה ימים לאחר ביצוע המופע חייב מפקד לתעד בתיק האישי?",options:["3 ימים","5 ימים","7 ימים","10 ימים"],correctAnswer:3,explanation:"התיעוד יעשה לא יאוחר מ-10 ימים לאחר ביצוע המופע.",source:"נוהל 4.4, עמ' 104"},
  {id:109,chapter:4,question:"מי רשאי לגשת לתיק האישי של הצוער?",options:["כל אחד","מפקדו הישיר, שרשרת הפיקוד עד מפקד הבהד, גורמי הדרכה, ומשא\"ן ביחידה","רק מפקד הבהד","רק היועץ/ת"],correctAnswer:1,explanation:"הרשאת גישה: למפקדו הישיר ושרשרת הפיקוד עד מפקד הבה\"ד/מפקד החיל, לגורמי ההדרכה (גפ\"ה/ק' צפ\"ה), לגורמי משא\"ן ביחידה, ולמפקד הקולט בתום ההכשרה.",source:"נוהל 4.4, עמ' 104"},
  {id:110,chapter:4,question:"עד מתי מתבצע מופע העברת מקל לכל המאוחר?",options:["ביום הסיום","לא יוקדם משבועיים טרם סיום ההכשרה","חודש לפני הסיום","שבוע לפני"],correctAnswer:1,explanation:"העברת המקל תתבצע טרם קליטתו של הצוער ביחידתו החדשה ולא יוקדם משבועיים טרם סיום ההכשרה.",source:"נוהל 4.5, עמ' 106"},
  {id:111,chapter:4,question:"מה כולל דוח העברת המקל?",options:["ציוני הסיום בלבד","פרטים אישיים, מידע מקצועי, נורמות וערכים, ומידע נוסף","לוח זמנים לחדש הראשון ביחידה","אישורי הסמכה בלבד"],correctAnswer:1,explanation:"על דוח העברת המקל לפרט: פרטים אישיים, מידע מקצועי (הישגים ופערי הסמכות), מידע אודות נורמות וערכים, ומידע נוסף.",source:"נוהל 4.5, עמ' 105"},
  {id:112,chapter:4,question:"מי אחראי על מילוי טופס העברת מקל?",options:["מפקד הבהד","מפקץ הצוער ממלא את הטופס, גפה הבהד שולחת לסמכויות","יועצת הבהד","קצין הסגל"],correctAnswer:1,explanation:"באחריות המפק\"ץ של הצוער למלא טופס העברת מקל. באחריות גפ\"ה הבה\"ד לשלוח לסמכויות את העברת מקל ותיק הצוער.",source:"נוהל 4.5, עמ' 106"},
  {id:113,chapter:4,question:"מה תפקיד הפסיכולוג/יועץ בתהליך ועדת הערכה לצוער?",options:["הוא זה שמחליט על הרחקה","עורך ראיון לצוער ונותן חוות דעת חיצונית שלא בשרשרת הפיקוד, בנסיבות מסוימות","אין לו תפקיד","כותב את תיק הוועדה"],correctAnswer:1,explanation:"הצוער יקיים שיחה פרונטלית עם יועץ מטעם הבה\"ד לטובת חוות דעת נוספת חיצונית שלא בשרשרת הפיקוד.",source:"נוהל 4.2, עמ' 97"},
  {id:114,chapter:4,question:"מה כולל מסמך בחירת צוער מצטיין מבחינת קריטריונים?",options:["ציון בלבד","ציוני גבוהים, חווד מפקד בולט לחיוב, ללא אירועי משמעת, וסוציומטרי עמיתים גבוה","רק חוות דעת עמיתים","ותק בשירות"],correctAnswer:1,explanation:"קריטריונים לצוער מצטיין: ציון סופי מעל 80, חווד מפקד – בולט לחיוב, ללא אירועי משמעת משמעותיים, סוציומטרי עמיתים גבוה.",source:"נוהל 4.3, עמ' 100"},
  {id:115,chapter:4,question:"כמה ימים לפני סוף הקורס צריך המ\"פ לסכם מועמדים למצטיין/למופת?",options:["יום לפני","יומיים לפני","3 ימים לפני","שבוע לפני"],correctAnswer:2,explanation:"באחריות המ\"פ או מקבילו בהמלצת סגל המפקדים לסכם את המועמדים להצטיינות ולמופת עד 3 ימים לפני סוף הקורס.",source:"נוהל 4.3, עמ' 99"},
  {id:116,chapter:4,question:"מה 'הגדרת צוער' לפי נוהל 4.4?",options:["כל חייל בצבא","כל מי שנמצא במסגרת רשמית של הכשרת קצונה, עובר למידה שמטרתה עיצוב זהותו המקצועית","חייל בקבע בלבד","חייל מעל גיל 21"],correctAnswer:1,explanation:"צוער – כל מי שנמצא במסגרת רשמית של הכשרת קצונה. הצוער עובר למידה שמטרתה לעצב את זהותו המקצועית, החילית והצה\"לית ולהכינו לתפקד כקצין.",source:"נוהל 4.4, עמ' 103"},
  {id:117,chapter:4,question:"מה עילות ההעלאה לוועדת הערכה לצוער?",options:["רצון הצוער לעזוב","אירוע חריג ערכי, הפסד ימי הכשרה, אי התאמה לקצונה, הערכת עמיתים חריגה, אי כשירות רפואית, אי עמידה בציוני הסף","ציון נמוך בלבד","בעיה משפחתית"],correctAnswer:1,explanation:"עילות העלאה לוועדה: אירוע חריג ערכי/נורמטיבי/משמעתי, הפסד ימי הכשרה מעל המותר, אי התאמה לקצונה, הערכת עמיתים חריגה, אי כשירות רפואית, אי עמידה בציוני הסף.",source:"נוהל 4.2, עמ' 96"},
  {id:118,chapter:4,question:"מה מגדיר 'אירוע חריג' בהקשר הרחקת איש סגל?",options:["כל טעות בעבודה","אירוע שאינו עומד בנורמות הערכיות, המצופות והמחויבות ממפקד בצה\"ל","כל קונפליקט עם עמיתים","אי עמידה במבחן"],correctAnswer:1,explanation:"אירוע חריג מוגדר כאירוע שאינו עומד בנורמות הערכיות, המצופות והמחויבות ממפקד בצה\"ל (אירועים משמעתיים וכו').",source:"נוהל 3.7, עמ' 88"},
  {id:119,chapter:4,question:"מה 'פערים משמעותיים בביצוע התפקיד' לפי נוהל 3.7?",options:["כישלון במבחן אחד","איש סגל שאינו מסוגל לבצע תפקידו בצורה ראויה, למרות ליווי וניסיונות שיפור","חיסורים","מחלוקת עם מפקד"],correctAnswer:1,explanation:"פערים משמעותיים בביצוע התפקיד – איש סגל שאינו מסוגל לבצע את תפקידו בצורה ראויה (הדרכתי ומקצועי), למרות ליווי אישי וניסיונות שיפור.",source:"נוהל 3.7, עמ' 88"},
  {id:120,chapter:4,question:"מי מוביל את הפורום הבכיר בבהד?",options:["מד\"רית מגמה","מפקד הבהד, כשהמשתתפים הם המגד\"ים והרע\"נים","קצין אגם","מפקד גפה"],correctAnswer:1,explanation:"פורום בכיר כולל את מפקד הבה\"ד, המג\"דים והרע\"נים המפקדים על ההכשרות בבה\"ד.",source:"נוהל 3.8, עמ' 91"},
  {id:121,chapter:5,question:"מהו 'מאמן' (סימולטור) לפי הגדרת התקן?",options:["מדריך אישי לצוער","התקן המחקה מרכיבים ממציאות הקרב לשם תרגול במיומנויות צבאיות","תוכנית לימוד ממוחשבת","כלי הערכה"],correctAnswer:1,explanation:"מאמן (סימולטור) הוא אמצעי הדרכה – התקן המחקה מרכיבים ממציאות הקרב לשם תרגול במיומנויות הצבאיות בתנאים דומים או קרובים לשדה הקרב.",source:"נוהל 5.1, עמ' 107"},
  {id:122,chapter:5,question:"תוך כמה חודשים מגעת המאמן ליחידה יש לסיים את תהליך הקליטה?",options:["חודש","חודשיים","שלושה חודשים","חצי שנה"],correctAnswer:2,explanation:"כלל הפעולות האמורות יבוצעו תוך שלושה חודשים מהגעת המאמן ליחידה.",source:"נוהל 5.1, עמ' 108"},
  {id:123,chapter:5,question:"מי מוביל את תהליך קליטת מאמן בבהד?",options:["מפקד הגדוד","מפקד הגפה","קצין אגם","מד\"רית המגמה"],correctAnswer:1,explanation:"תהליך קליטה של מאמן יובל ע\"י מפקד הגפ\"ה בבה\"ד.",source:"נוהל 5.1, עמ' 107"},
  {id:124,chapter:5,question:"מה נדרש כתב המינוי לקליטת מאמן?",options:["חתימת מפקד הגדוד","חתימת מפקד הבהד, עבור מפקד הגפה והפונקציות המקצועיות המוגדרות","חתימת ענף הדרכה בלבד","אין צורך בכתב מינוי"],correctAnswer:1,explanation:"יש להוציא כתב מינוי בחתימת מפקד הבה\"ד לקליטת המאמן עבור מפקד הגפ\"ה והפונקציות המקצועיות המוגדרות לתהליך.",source:"נוהל 5.1, עמ' 107"},
  {id:125,chapter:5,question:"מה 'מסמך תפיסת הפעלה' שנכתב למאמן חייב לכלול?",options:["עלות המאמן ותקציב","ניתוח כשירויות, הכשרות בהן ישולב, עיתוי שילוב, ומערך בקרה וחניכה מחייב","לוח תחזוקה שנתי","שמות מפעילי המאמן"],correctAnswer:1,explanation:"מסמך תפיסת הפעלה יכלול: ניתוח הכשירויות המושגות, ההכשרות בהם ישולב המאמן, עיתוי השילוב ומטרותיו, והגדרת מערך הבקרה והחניכה בכל תרגול.",source:"נוהל 5.1, עמ' 108"},
  {id:126,chapter:5,question:"מה כולל 'ניסוי כלים מלא' במאמן?",options:["בדיקת מראה בלבד","בדיקת תקינות טכנית, אינטראקציות בקרה, כלל תרחישים, דפי הערכה, ותיקוף זמנים","בדיקת כח אדם","בדיקת תקציב"],correctAnswer:1,explanation:"ניסוי כלים מלא כולל: בדיקת תקינות טכנית, בדיקת אינטראקציות בקרה וחניכה, בדיקת כלל התרחישים, בדיקת יעילות דפי הערכה, ותיקוף הזמנים הנדרשים.",source:"נוהל 5.1, עמ' 109"},
  {id:127,chapter:5,question:"מה כוללות 'תשתיות הדרכה' לפי הגדרת נוהל 5.3?",options:["ציוד אישי לחיילים","כל מבנה שמטרתו קיום למידה או אימון: כיתות, מטווחים, לשביות ומאמנים","תקציב ההדרכה","מערכת הקמפוס הדיגיטלי"],correctAnswer:1,explanation:"תשתיות הדרכה – כל מבנה שמטרתו לקיים באמצעותו למידה או אימון לרבות כיתות מסוגים שונים, מטווחים, לש\"ביות ומאמנים.",source:"נוהל 5.3, עמ' 113"},
  {id:128,chapter:5,question:"מי אחראי על אחזקת תשתיות ההדרכה בכלל?",options:["מפקד הבהד","נגדת הכיתות בהובלת רע\"ן הדרכה","מפקד הגדוד","קצין לוגיסטיקה"],correctAnswer:1,explanation:"האחריות הכוללת על אחזקת תשתיות ההדרכה הינה אחריות של נגדת הכיתות בהובלת רע\"ן הדרכה.",source:"נוהל 5.3, עמ' 113"},
  {id:129,chapter:5,question:"מה חובת רשימת תכולה לכל תשתית הדרכה?",options:["אין חובה","רשימה עדכנית תהיה תלויה במקום בולט בתוך המבנה עצמו","רשימה נשמרת רק במשרד","רשימה מעודכנת פעם בשנה"],correctAnswer:1,explanation:"רשימת התכולה תהיה תלויה במקום בולט בתוך המבנה עצמו.",source:"נוהל 5.3, עמ' 113"},
  {id:130,chapter:5,question:"כמה פעמים בחציון מתקיים דיון סטטוס תקינות כיתות?",options:["אחת לרבעון","אחת לחציון","אחת לשנה","פעמיים בחציון"],correctAnswer:1,explanation:"אחת לחציון יתקיים דיון סטטוס תקינות כיתות בראשות רע\"ן ההדרכה.",source:"נוהל 5.3, עמ' 115"},
  {id:131,chapter:5,question:"מה 'אמצעי הדרכה' לפי הגדרת נוהל 5.1?",options:["ציוד לחימה","כלים שבאמצעותם מונגשת ההדרכה ללומד","תקציב ההדרכה","כוח אדם"],correctAnswer:1,explanation:"אמצעי הדרכה – כלים באמצעות מונגשת ההדרכה ללומד.",source:"נוהל 5.1, עמ' 107"},
  {id:132,chapter:5,question:"מה 'התוויית הדרכה לאמל\"ח' לפי נוהל 5.2?",options:["רשימת תיקון","פקודה הנכתבת ע\"י מחלקת הדרכה ומגדירה את אופן שילוב ההדרכה על האמל\"ח בהכשרות","תיק יסוד של האמל\"ח","הוראות תפעול"],correctAnswer:1,explanation:"התוויית הדרכה לאמל\"ח – פקודה הנכתבת ע\"י מחלקת הדרכה ומגדירה את אופן שילוב ההדרכה על האמל\"ח בהכשרות.",source:"נוהל 5.2, עמ' 110"},
  {id:133,chapter:5,question:"מתי מופצת הוראת הקליטה האגמית לבהד לפני תחילת הטמעת האמלח?",options:["חודש לפני","שלושה חודשים לפני","כחצי שנה טרם תחילת ההטמעה","שנה לפני"],correctAnswer:2,explanation:"הוראת הקליטה האג\"מית נכתבת ע\"י החיל ומופצת כפקודה לבית הספר כחצי שנה טרם תחילת ההטמעה בהכשרות.",source:"נוהל 5.2, עמ' 110"},
  {id:134,chapter:5,question:"מי עומד בראש 'ועדת קליטה' לאמלח חדש?",options:["מפקד הגדוד","מפקד בדרגת רס\"ן, שמוקם ע\"י מפקד בית הספר","מפקד הגפה","קצין לוגיסטיקה"],correctAnswer:1,explanation:"מפקד בית הספר יקים ועדת קליטה בראשות מפקד בדרגת רס\"ן.",source:"נוהל 5.2, עמ' 111"},
  {id:135,chapter:5,question:"מה תפקיד ה'גרעין הקמה' בקליטת אמלח?",options:["אחזקה שוטפת","למידת האמלח בתעשייה המפתחת, פיתוח תכולות הדרכה, וכלי הערכה, והכנת הסגלים","תיאום עם ספק","ביצוע מבחנים"],correctAnswer:1,explanation:"גרעין ההקמה יעסוק בלמידת האמל\"ח בתעשיה המפתחת, פיתוח תכולות ההדרכה – מארזי הדרכה וכלי הערכה, וכן הכנת הסגלים לאמל\"ח החדש לקראת מחזור הכשרה.",source:"נוהל 5.2, עמ' 111"},
  {id:136,chapter:5,question:"מה כולל הגאנט שמנהלת ועדת קליטה אמלח?",options:["לוח שיעורים","מעקב אחר הגעת האמצעים, פיתוח תכולות הדרכה, הכנת סגלים, ועדכון תיקי יסוד","תקציב ולוגיסטיקה בלבד","ישיבות ועדה"],correctAnswer:1,explanation:"הגאנט כולל מעקב אחר: הגעת האמצעים, פיתוח תכולות הדרכה, הכנת הסגלים, ועדכון תיקי היסוד הרלוונטיים.",source:"נוהל 5.2, עמ' 111"},
  {id:137,chapter:5,question:"מה 'הוראת קליטה אגמית' לאמלח?",options:["הוראות תפעול בלבד","הוראה הנכתבת ע\"י החיל ומכילה תפוצת האמלח, הוראות מקצועיות, בטיחות, סיווג ולוחות זמנים","תיק יסוד מחודש","הוראת ביטול"],correctAnswer:1,explanation:"הוראת קליטה אג\"מית – הוראה הנכתבת ע\"י 'המשתמש' (החיל). כוללת: תפוצת האמל\"ח, הוראות מקצועיות, הוראות הבטיחות, סיווג בטחוני, תדירות שמירת כשירות ולוחות הזמנים לקליטה.",source:"נוהל 5.2, עמ' 110"},
  {id:138,chapter:5,question:"מה מטרת 'מסדר תקינות תשתית' לפני פתיחת מחזור?",options:["בדיקת נוכחות","בדיקת תקינות תשתיות ההדרכה ותכולתן ע\"י רע\"ן הדרכה/נגדת כיתות עם כלל גורמי מטה","הקצאת כיסאות","הפקת לקחים"],correctAnswer:1,explanation:"טרם פתיחת מחזור יתקיים מסדר על תשתיות ההדרכה בראשות רע\"ן הדרכה או ע\"י נגדת הכיתות בהשתתפות כלל גורמי המטה אשר אחראיים על תקינות התכולה.",source:"נוהל 5.3, עמ' 115"},
  {id:139,chapter:5,question:"כמה חודשים אחורה יש לשמור מסמכי ניהול תשתיות הדרכה?",options:["שלושה חודשים","חצי שנה","שנה","שנתיים"],correctAnswer:2,explanation:"על החומר להיות מתועד למשך שנה אחורה.",source:"נוהל 5.3, עמ' 116"},
  {id:140,chapter:5,question:"כמה פעמים ברבעון מפיץ בעל התפקיד הממונה דוח סטטוס תקינות כיתות?",options:["אחת לחודש","אחת לרבעון","פעמיים ברבעון","פעם בשנה"],correctAnswer:1,explanation:"אחת לרבעון יפיץ בעל התפקיד הממונה דוח סטטוס תקינות כיתות.",source:"נוהל 5.3, עמ' 115"},
  {id:141,chapter:5,question:"מה מחייב אישור חריג מחתימת מפקד הבהד בנוגע למאמן?",options:["כל שימוש במאמן","כל חריגה מנוהל קליטת מאמן","רכישת מאמן חדש","עדכון תרחיש"],correctAnswer:1,explanation:"חריגה מנוהל זה מחייבת אישור חתום ע\"י מפקד הבה\"ד.",source:"נוהל 5.1, עמ' 108"},
  {id:142,chapter:5,question:"מה מאפשר מסדר על תשתיות לאחר כל שימוש?",options:["עדכון לוח שיעורים","בדיקת תקינות התשתית והתכולה ע\"י בעל התפקיד הממונה על כל תשתית","תיאום עתידי","ביצוע ניקוי"],correctAnswer:1,explanation:"יתקיים מסדר תקינות התשתית והתכולה על-ידי בעל התפקיד הממונה על התשתית ההדרכתית לאחר כל שימוש בתשתית.",source:"נוהל 5.3, עמ' 115"},
  {id:143,chapter:5,question:"כמה שבועות קדימה חייב בעל תפקיד לנהל טבלת תיאומים לתשתית הדרכה?",options:["יומיים","שלושה ימים","שבוע לפחות","שבועיים"],correctAnswer:2,explanation:"באחריות בעל התפקיד הממונה לנהל טבלת תיאומים לכל הפחות שבוע קדימה המגדירה למי מתואמת כל תשתית הדרכתית.",source:"נוהל 5.3, עמ' 115"},
  {id:144,chapter:5,question:"מה מטרת ביצוע 'ניסוי כלים' עבור תרחישים במאמן?",options:["בדיקה ויזואלית בלבד","בדיקת כל תרחיש, כולל יעילות דפי הערכה ותיקוף זמנים נדרשים לתרגיל מוצלח","בדיקת כח אדם","בדיקת מחיר"],correctAnswer:1,explanation:"ניסוי כלים יכלול בדיקת כלל התרחישים, בדיקת יעילות ורלוונטיות דפי ההערכה, ותיקוף הזמנים הנדרשים לביצוע תרגיל מוצלח כולל הכנות ותחקור.",source:"נוהל 5.1, עמ' 109"},
  {id:145,chapter:5,question:"מה כולל תיקון ועדכון תיקי יסוד בעקבות קליטת מאמן?",options:["שינוי כיסוי בלבד","עדכון כלל תיקי היסוד וגלום השימוש במאמן בכל הסעיפים הרלוונטיים, כולל ניתוח כשירויות","הוספת נספח בלבד","שינוי שם הקורס"],correctAnswer:1,explanation:"יש לעדכן את כלל תיקי היסוד ולגלם את השימוש במאמן בכלל הסעיפים הרלוונטיים בתיק היסוד לרבות בטבלת ניתוח הכשירויות ואופן השגת הכשירות.",source:"נוהל 5.1, עמ' 109"},
  {id:146,chapter:5,question:"מה ייחודו של 'מדור הדרכה מקצועי' שממונה על האמלח לאורך זמן?",options:["מדור זמני","אחראי על האמלח מול גורמי בית הספר והחיל לאורך זמן, גם בתום תקופת הקליטה וההטמעה","אחראי רק בתקופת הקליטה","מנהל רשימות"],correctAnswer:1,explanation:"יש להגדיר מדור הדרכה מקצועי אשר יהיה אחראי על האמל\"ח מול גורמי בית הספר והחיל לאורך זמן, גם בתום תקופת הקליטה וההטמעה.",source:"נוהל 5.2, עמ' 112"},
  {id:147,chapter:5,question:"מה 'אמצעים' לפי הגדרת נוהל 5.2?",options:["ציוד אישי לחיילים","אמצעי לחימה, אמצעי סיוע, אמצעי הדרכה הנוגעים ללחימה, מערכות מידע ושליטה","תקציב בלבד","כח אדם"],correctAnswer:1,explanation:"אמצעים – אמצעי לחימה, אמצעי סיוע ללחימה, אמצעי הדרכה הנוגעים ללחימה, מערכות מידע, מערכות שליטה ובקרה.",source:"נוהל 5.2, עמ' 110"},
  {id:148,chapter:5,question:"מה אחריות 'ראש ועדת הקליטה' לאמלח?",options:["אחזקה שוטפת","קיום דיוני סטטוס אחת לחודש והפצת סיכום פערים לגורם החיילי הרלוונטי","כתיבת פקודות","הדרכת סגל בלבד"],correctAnswer:1,explanation:"באחריות ראש ועדת הקליטה לקיים דיוני סטטוס אחת לחודש ולהפיץ סיכום הפערים לגורם החיילי הרלוונטי.",source:"נוהל 5.2, עמ' 112"},
  {id:149,chapter:5,question:"מה נדרש לפתח עבור כל תרחיש במאמן?",options:["מצגת כללית בלבד","תרחישים שונים ומגוונים ודפי הערכה ייעודיים לכל תרחיש","לוח שיעורים","בחינה כתובה"],correctAnswer:1,explanation:"נדרש לכתוב תרחישים שונים ומגוונים עבור כל אחד מסוגי המתאמנים, ולפתח דפי הערכה ייעודיים לכל תרחיש במאמן.",source:"נוהל 5.1, עמ' 108"},
  {id:150,chapter:5,question:"מה האחריות על בעל התפקיד הממונה לגבי מפתחות תשתיות הדרכה?",options:["אין אחריות מיוחדת","החזקת מפתחות רזרביים לכלל תשתיות ההדרכה הננעלות","מסירת מפתחות לסגן בלבד","בניית כספת"],correctAnswer:1,explanation:"באחריות בעל התפקיד הממונה להחזיק מפתחות רזרבים לכלל תשתיות ההדרכה הננעלות.",source:"נוהל 5.3, עמ' 115"},
];

// Shuffle array utility
function shuffleArray(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// Get 10 random questions from selected chapters
function getQuizQuestions(selectedChapterIds) {
  const pool = QUIZ_QUESTIONS_BANK.filter(q => selectedChapterIds.includes(q.chapter));
  const shuffled = shuffleArray(pool);
  return shuffled.slice(0, 10);
}

