function PillHeader({title, subtitle, accentColor}) {
  const fill = accentColor || "#D4806A";
  const h = subtitle ? 170 : 140;
  return (
    <div className="pill-header-wrap">
      <div className="pill-header-svg-wrap">
        <svg viewBox={`0 0 500 ${h}`} preserveAspectRatio="none" style={{display:"block",width:"100%",height:"auto"}}>
          <path d={`M0,0 L500,0 L500,${h} L450,${h} Q250,${h-50} 50,${h} L0,${h} Z`} fill={fill}/>
        </svg>
        <div className="pill-logos-overlay">
          <img src={gapalogo} alt="gapa" className="pill-logo-img"/>
          <img src={bhdlogo}  alt="bhd"  className="pill-logo-img"/>
        </div>
        <div className="pill-text-overlay">
          {subtitle && <div className="pill-subtitle">{subtitle}</div>}
          <div className="pill-title">{title}</div>
        </div>
      </div>
    </div>
  );
}

